    def gen_curset(self, operands: List) -> bytes:
        if self.version < 4:
            if not getattr(getattr(self, "compiler", None), "_is_classic_parser", False):
                # ZILF-dialect / toy programs keep the hard V3 gate
                raise ValueError("CURSET requires V4 or later")
            self._warn("CURSET (set_cursor) is V4+; emitting anyway for "
                       "extended-V3 interpreters")
        code = bytearray()
        code.append(0xEF)  # SET_CURSOR (VAR:0x0F)
        if len(operands) == 1:
            if self.version < 6:
                raise ValueError("CURSET with 1 operand requires V6")
            op1_type, op1_val = self._get_operand_type_and_value_ext(operands[0])
            if op1_type == 0:
                code.append(0x3F)
                code.append((op1_val >> 8) & 0xFF)
                code.append(op1_val & 0xFF)
            elif op1_type == 1:
                code.append(0x7F)
                code.append(op1_val & 0xFF)
            else:
                code.append(0xBF)
                code.append(op1_val & 0xFF)
        elif len(operands) == 2:
            op1_type, op1_val = self._get_operand_type_and_value_ext(operands[0])
            op2_type, op2_val = self._get_operand_type_and_value_ext(operands[1])
            t1 = op1_type if op1_type <= 2 else 3
            t2 = op2_type if op2_type <= 2 else 3
            code.append((t1 << 6) | (t2 << 4) | 0x0F)
            if op1_type == 0:
                code.append((op1_val >> 8) & 0xFF)
                code.append(op1_val & 0xFF)
            else:
                code.append(op1_val & 0xFF)
            if op2_type == 0:
                code.append((op2_val >> 8) & 0xFF)
                code.append(op2_val & 0xFF)
            else:
                code.append(op2_val & 0xFF)
        else:
            raise ValueError(f"CURSET requires 1 or 2 operands, got {len(operands)}")
        return bytes(code)

    def gen_set_cursor(self, operands: List[ASTNode]) -> bytes:
        """Generate SET_CURSOR (V4+ - position cursor).

        <SET_CURSOR line column window> sets cursor position.
        Alias for CURSET. VAR:0x0F.

        Returns:
            bytes: Z-machine code
        """
        # Delegate to CURSET implementation
        return self.gen_curset(operands)

